const { Knock: KnockMgmt } = require("@knocklabs/mgmt");
const { Knock } = require("@knocklabs/node");

const knockMgmt = new KnockMgmt(process.env.KNOCK_SERVICE_TOKEN);

async function test() {
  try {
    const wf = await knockMgmt.workflows.upsert("test-workflow", {
      name: "Test Workflow",
      environment: "development",
      steps: [
        {
          ref: "branch_step",
          type: "branch",
          name: "Branch on channel preference",
          settings: {
            branches: [
              {
                name: "Email Branch",
                terminates: true,
                conditions: [
                  {
                    argument: "email",
                    variable: "data.channel_preference",
                    operator: "equal_to"
                  }
                ],
                steps: [
                  {
                    ref: "email_step",
                    type: "channel",
                    channel_key: "mailtrap",
                    template: {
                      settings: {
                        subject: "Hello {{ recipient.name }}",
                        html_body: "This is an email for {{ recipient.name }}"
                      }
                    }
                  }
                ]
              },
              {
                name: "Default Branch",
                terminates: true,
                default: true,
                steps: [
                  {
                    ref: "in_app_step",
                    type: "channel",
                    channel_key: "in-app",
                    template: {
                      settings: {
                        markdown_body: "This is an in-app message for {{ recipient.name }}"
                      }
                    }
                  }
                ]
              }
            ]
          }
        }
      ]
    });
    console.log("Success:", JSON.stringify(wf, null, 2));
  } catch (e) {
    console.error("Error:", e.response?.data || e.message);
  }
}

test();

